from flask import Flask, request, jsonify
from functools import wraps
import jwt

app = Flask(__name__)

# Configuration for different signing algorithms
ALGORITHMS = {
    'HS256': 'your_hmac_secret_key',
    'RS256': 'your_rsa_private_key'
}

def verify_token(algorithm):
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            token = request.headers.get('Authorization')
            if not token:
                return jsonify({'error': 'Missing token'}), 401
            
            try:
                payload = jwt.decode(token, ALGORITHMS[algorithm], algorithms=[algorithm])
                request.payload = payload
                return f(*args, **kwargs)
            except jwt.ExpiredSignatureError:
                return jsonify({'error': 'Token expired'}), 401
            except jwt.InvalidTokenError:
                return jsonify({'error': 'Invalid token'}), 401
        
        return wrapper
    return decorator

@app.route('/protected', methods=['GET'])
@verify_token('HS256')
def protected():
    user_id = request.payload['user_id']
    return jsonify({'message': f'Access granted for user {user_id}'})

@app.route('/public-api', methods=['GET'])
@verify_token('RS256')
def public_api():
    data = request.payload.get('data')
    return jsonify({'message': 'Public API accessed successfully', 'data': data})

if __name__ == '__main__':
    app.run(debug=True)